// src/App.js
import React, { useState, useEffect } from 'react';
import PropertyFilter from './components/PropertyFilter';
import PropertyList from './components/PropertyList';
import PropertyDetail from './components/PropertyDetail';
import { fetchAllProperties, fetchPropertyById, filterProperties } from './utils/api';
import './App.css';

function App() {
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedProperty, setSelectedProperty] = useState(null);
  const [isFiltered, setIsFiltered] = useState(false);

  useEffect(() => {
    loadProperties();
  }, []);

  const loadProperties = async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await fetchAllProperties();
      setProperties(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleFilter = async (criteria) => {
    try {
      setLoading(true);
      setError(null);
      const data = await filterProperties(criteria);
      setProperties(data);
      setIsFiltered(true);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleClear = () => {
    setIsFiltered(false);
    loadProperties();
  };

  const handleSelectProperty = async (property) => {
    try {
      const detail = await fetchPropertyById(property.id);
      setSelectedProperty(detail);
    } catch (err) {
      setError(err.message);
    }
  };

  const handleBack = () => {
    setSelectedProperty(null);
  };

  if (selectedProperty) {
    return (
      <div className="App">
        <h1>Real Estate Listing Management System</h1>
        <PropertyDetail property={selectedProperty} onBack={handleBack} />
      </div>
    );
  }

  return (
    <div className="App">
      <h1>Real Estate Listing Management System</h1>
      <PropertyFilter onFilter={handleFilter} onClear={handleClear} loading={loading} />
      <PropertyList 
        properties={properties} 
        loading={loading} 
        error={error} 
        onSelect={handleSelectProperty} 
      />
    </div>
  );
}

export default App;
